// Phase 11 v12.1: Memory Layout & Manual Allocation
// 데이터 레이아웃과 수동 메모리 관리

use std::alloc::{alloc, dealloc, Layout};
use std::mem;
use std::ptr::{self, NonNull};

// =============================================================================
// Demo 1: 기본 레이아웃 - 크기와 정렬
// =============================================================================

fn demo_basic_layout() {
    println!("\n=== Demo 1: 기본 레이아웃 - 크기와 정렬 ===");

    // [타입들의 정렬 속성]
    println!("  [정렬 정보]");
    println!("    u8:  크기={} bytes, 정렬={} bytes", mem::size_of::<u8>(), mem::align_of::<u8>());
    println!("    u16: 크기={} bytes, 정렬={} bytes", mem::size_of::<u16>(), mem::align_of::<u16>());
    println!("    u32: 크기={} bytes, 정렬={} bytes", mem::size_of::<u32>(), mem::align_of::<u32>());
    println!("    u64: 크기={} bytes, 정렬={} bytes", mem::size_of::<u64>(), mem::align_of::<u64>());

    // [구조체 레이아웃]
    #[repr(Rust)]
    struct DefaultLayout {
        a: u8,
        b: u32,
        c: u16,
    }

    println!("\n  [DefaultLayout (repr Rust)]");
    println!("    예상: 1 + 4 + 2 = 7 bytes");
    println!("    실제: {} bytes", mem::size_of::<DefaultLayout>());
    println!("    정렬: {} bytes", mem::align_of::<DefaultLayout>());
    println!("    → {} bytes 패딩이 포함됨!", mem::size_of::<DefaultLayout>() - 7);

    // [Layout 객체로 확인]
    let layout = Layout::new::<DefaultLayout>();
    println!("\n  [Layout 객체]");
    println!("    크기: {} bytes", layout.size());
    println!("    정렬: {} bytes", layout.align());
}

// =============================================================================
// Demo 2: repr(C) - C 호환 레이아웃
// =============================================================================

#[repr(C)]
struct CCompatible {
    a: u8,   // 0x00
    b: u32,  // 0x04 (정렬 위해 패딩)
    c: u16,  // 0x08
}

fn demo_repr_c() {
    println!("\n=== Demo 2: repr(C) - C 호환 레이아웃 ===");

    println!("  [CCompatible (repr C)]");
    println!("    크기: {} bytes", mem::size_of::<CCompatible>());
    println!("    정렬: {} bytes", mem::align_of::<CCompatible>());

    // [필드 오프셋 계산]
    let dummy = CCompatible { a: 0, b: 0, c: 0 };
    let base = &dummy as *const _ as usize;

    unsafe {
        let a_offset = &dummy.a as *const _ as usize - base;
        let b_offset = &dummy.b as *const _ as usize - base;
        let c_offset = &dummy.c as *const _ as usize - base;

        println!("\n  [필드 오프셋]");
        println!("    a @ 0x{:02x} (1 byte)", a_offset);
        println!("    b @ 0x{:02x} (4 bytes, 패딩 at 0x01-0x03)", b_offset);
        println!("    c @ 0x{:02x} (2 bytes)", c_offset);
    }

    println!("\n  [메모리 이미지]");
    println!("    0x00: [a 값]");
    println!("    0x01-0x03: [패딩]");
    println!("    0x04-0x07: [b 값]");
    println!("    0x08-0x09: [c 값]");
    println!("    0x0A-0x0B: [패딩]");
}

// =============================================================================
// Demo 3: repr(packed) - 메모리 절약
// =============================================================================

#[repr(packed)]
struct Packed {
    a: u8,
    b: u32,
    c: u16,
}

fn demo_repr_packed() {
    println!("\n=== Demo 3: repr(packed) - 메모리 절약 ===");

    println!("  [Packed (repr packed)]");
    println!("    크기: {} bytes", mem::size_of::<Packed>());
    println!("    정렬: {} bytes", mem::align_of::<Packed>());

    // [비교]
    println!("\n  [비교]");
    println!("    repr(C):      {} bytes (패딩 포함, CPU 친화적)", mem::size_of::<CCompatible>());
    println!("    repr(packed): {} bytes (패딩 없음, 메모리 효율)", mem::size_of::<Packed>());
    println!("    절약: {} bytes", mem::size_of::<CCompatible>() - mem::size_of::<Packed>());

    println!("\n  [경고]");
    println!("    repr(packed)은 메모리는 절약하지만,");
    println!("    CPU 접근이 느려질 수 있습니다!");
}

// =============================================================================
// Demo 4: 수동 메모리 할당과 해제
// =============================================================================

fn demo_manual_allocation() {
    println!("\n=== Demo 4: 수동 메모리 할당과 해제 ===");

    unsafe {
        // [1단계] Layout 정의
        let layout = Layout::new::<u32>();
        println!("  [1] Layout 정의");
        println!("    크기: {} bytes", layout.size());
        println!("    정렬: {} bytes", layout.align());

        // [2단계] 메모리 할당
        let ptr = alloc(layout) as *mut u32;
        println!("\n  [2] 메모리 할당");

        if ptr.is_null() {
            panic!("메모리 할당 실패!");
        }
        println!("    주소: {:p}", ptr);
        println!("    상태: 할당됨 ✓");

        // [3단계] 초기화
        ptr::write(ptr, 42);
        println!("\n  [3] 초기화");
        println!("    값 쓰기: 42");

        // [4단계] 사용
        let value = ptr::read(ptr);
        println!("\n  [4] 사용");
        println!("    값 읽기: {}", value);

        // [5단계] 해제
        dealloc(ptr as *mut u8, layout);
        println!("\n  [5] 메모리 해제");
        println!("    상태: 해제됨 ✓");

        println!("\n  [생명주기]");
        println!("    alloc() → write() → read() → dealloc()");
        println!("    이 순서를 어기면 Undefined Behavior!");
    }
}

// =============================================================================
// Demo 5: 배열 할당
// =============================================================================

fn demo_array_allocation() {
    println!("\n=== Demo 5: 배열 할당 ===");

    unsafe {
        const CAPACITY: usize = 10;

        // [1단계] 배열 레이아웃 생성
        let layout = Layout::array::<i32>(CAPACITY).unwrap();
        println!("  [배열 할당]");
        println!("    요소 개수: {}", CAPACITY);
        println!("    요소 크기: {} bytes", mem::size_of::<i32>());
        println!("    총 크기: {} bytes", layout.size());

        // [2단계] 메모리 할당
        let ptr = alloc(layout) as *mut i32;
        if ptr.is_null() {
            panic!("배열 할당 실패!");
        }
        println!("    할당 주소: {:p}", ptr);

        // [3단계] 배열 초기화
        println!("\n  [배열 초기화]");
        for i in 0..CAPACITY {
            ptr::write(ptr.add(i), (i as i32) * 10);
        }
        println!("    {} 개 요소 초기화 완료", CAPACITY);

        // [4단계] 배열 사용
        println!("\n  [배열 출력]");
        for i in 0..CAPACITY {
            let value = ptr::read(ptr.add(i));
            print!("{} ", value);
        }
        println!();

        // [5단계] 배열 해제
        dealloc(ptr as *mut u8, layout);
        println!("\n  [메모리 해제 완료]");
    }
}

// =============================================================================
// Demo 6: 안전한 할당기 (Safe Wrapper)
// =============================================================================

/// [안전 인터페이스] 수동 할당을 안전하게 감싼 할당기
struct SafeAllocator;

impl SafeAllocator {
    /// [안전] T 타입의 단일 값 할당
    unsafe fn allocate<T>() -> Option<NonNull<T>> {
        let layout = Layout::new::<T>();
        let ptr = alloc(layout) as *mut T;
        NonNull::new(ptr)
    }

    /// [안전] T 타입의 배열 할당
    unsafe fn allocate_array<T>(len: usize) -> Option<NonNull<T>> {
        let layout = Layout::array::<T>(len).ok()?;
        let ptr = alloc(layout) as *mut T;
        NonNull::new(ptr)
    }

    /// [안전] 할당된 메모리 해제
    unsafe fn deallocate<T>(ptr: NonNull<T>) {
        let layout = Layout::new::<T>();
        dealloc(ptr.as_ptr() as *mut u8, layout);
    }

    /// [안전] 배열 메모리 해제
    unsafe fn deallocate_array<T>(ptr: NonNull<T>, len: usize) {
        let layout = Layout::array::<T>(len).unwrap();
        dealloc(ptr.as_ptr() as *mut u8, layout);
    }
}

/// [안전한 박스] 수동 할당 + RAII
struct SafeBox<T> {
    ptr: NonNull<T>,
}

impl<T> SafeBox<T> {
    fn new(value: T) -> Self {
        unsafe {
            let ptr = SafeAllocator::allocate::<T>().expect("할당 실패!");
            ptr::write(ptr.as_ptr(), value);
            SafeBox { ptr }
        }
    }

    fn get(&self) -> &T {
        unsafe { &*self.ptr.as_ptr() }
    }

    fn get_mut(&mut self) -> &mut T {
        unsafe { &mut *self.ptr.as_ptr() }
    }
}

impl<T> Drop for SafeBox<T> {
    fn drop(&mut self) {
        unsafe {
            ptr::read(self.ptr.as_ptr());  // Drop 실행
            SafeAllocator::deallocate(self.ptr);
        }
    }
}

fn demo_safe_allocator() {
    println!("\n=== Demo 6: 안전한 할당기 ===");

    // [케이스 1] 단일 값 할당
    {
        let mut box_val = SafeBox::new(100_i32);
        println!("  [SafeBox 할당]");
        println!("    값: {}", box_val.get());

        *box_val.get_mut() = 200;
        println!("    수정 후: {}", box_val.get());

        println!("    (drop 실행 시 자동 해제)");
    }  // 여기서 자동 해제됨

    // [케이스 2] 배열 할당
    unsafe {
        println!("\n  [배열 할당]");
        let arr = SafeAllocator::allocate_array::<i32>(5).expect("할당 실패!");

        // 초기화
        for i in 0..5 {
            ptr::write(arr.as_ptr().add(i), (i as i32) * 10);
        }
        println!("    배열 초기화: 0, 10, 20, 30, 40");

        // 사용
        println!("    배열 읽기:");
        for i in 0..5 {
            print!("{} ", ptr::read(arr.as_ptr().add(i)));
        }
        println!();

        // 해제
        SafeAllocator::deallocate_array(arr, 5);
        println!("    배열 해제 완료");
    }

    println!("\n  [메시지]");
    println!("    • 내부: unsafe 메모리 관리");
    println!("    • 외부: 안전한 인터페이스");
    println!("    • 이것이 러스트의 철학입니다!");
}

