// =============================================================================
// Tests
// =============================================================================

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_layout_sizes() {
        assert_eq!(mem::size_of::<u8>(), 1);
        assert_eq!(mem::size_of::<u16>(), 2);
        assert_eq!(mem::size_of::<u32>(), 4);
        assert_eq!(mem::size_of::<u64>(), 8);
    }

    #[test]
    fn test_layout_alignment() {
        assert_eq!(mem::align_of::<u8>(), 1);
        assert_eq!(mem::align_of::<u16>(), 2);
        assert_eq!(mem::align_of::<u32>(), 4);
        assert_eq!(mem::align_of::<u64>(), 8);
    }

    #[test]
    fn test_c_compatible() {
        let layout = Layout::new::<CCompatible>();
        assert!(layout.size() >= 7);  // 최소 7바이트
        assert!(layout.align() >= 1);
    }

    #[test]
    fn test_packed() {
        assert!(mem::size_of::<Packed>() <= mem::size_of::<CCompatible>());
    }

    #[test]
    fn test_manual_allocation() {
        unsafe {
            let layout = Layout::new::<i32>();
            let ptr = alloc(layout) as *mut i32;
            assert!(!ptr.is_null());

            ptr::write(ptr, 42);
            assert_eq!(ptr::read(ptr), 42);

            dealloc(ptr as *mut u8, layout);
        }
    }

    #[test]
    fn test_safe_box() {
        let box_val = SafeBox::new(100_i32);
        assert_eq!(*box_val.get(), 100);
    }

    #[test]
    fn test_array_layout() {
        let layout = Layout::array::<i32>(10).unwrap();
        assert_eq!(layout.size(), 40);  // 4 * 10
    }
}
